#!/usr/bin/env node
/**
 * Report Footer Generator
 *
 * Standardizes report footers across all OpsPal-generated reports.
 * Ensures consistent branding with "Generated by OpsPal by RevPal".
 *
 * @module report-footer-generator
 * @version 1.0.0
 */

/**
 * Generate standardized report footer
 *
 * @param {Object} options - Footer options
 * @param {string} options.tool - Tool/agent/framework name (e.g., "CPQ Assessment Framework")
 * @param {string} [options.version] - Tool version (e.g., "v2.0")
 * @param {string} [options.method] - Method used (e.g., "API", "Metadata", "Hybrid")
 * @param {string} [options.reportType] - Type of report (e.g., "Executive Summary", "Detailed Analysis")
 * @param {boolean} [options.includeTimestamp=true] - Include generation timestamp
 * @param {string} [options.format='markdown'] - Output format ('markdown', 'html', 'text')
 * @returns {string} Formatted footer
 *
 * @example
 * // Markdown footer with all options
 * generateFooter({
 *   tool: 'CPQ Assessment Framework',
 *   version: 'v2.0',
 *   method: 'API',
 *   reportType: 'Executive Summary'
 * });
 * // Returns:
 * // ---
 * // *Generated by OpsPal by RevPal*
 * // Tool: CPQ Assessment Framework v2.0 | Method: API | Report Type: Executive Summary
 * // Generated: 2025-10-09T12:34:56.789Z
 *
 * @example
 * // HTML footer
 * generateFooter({
 *   tool: 'Automation Auditor',
 *   format: 'html'
 * });
 * // Returns HTML footer element
 */
function generateFooter(options = {}) {
  const {
    tool,
    version,
    method,
    reportType,
    includeTimestamp = true,
    format = 'markdown'
  } = options;

  if (!tool) {
    throw new Error('Tool name is required for report footer');
  }

  const timestamp = new Date().toISOString();
  const toolWithVersion = version ? `${tool} ${version}` : tool;

  // Build metadata line
  const metadata = [];
  metadata.push(`Tool: ${toolWithVersion}`);
  if (method) metadata.push(`Method: ${method}`);
  if (reportType) metadata.push(`Report Type: ${reportType}`);

  const metadataLine = metadata.join(' | ');

  // Format-specific rendering
  switch (format) {
    case 'markdown':
      return generateMarkdownFooter(metadataLine, timestamp, includeTimestamp);

    case 'html':
      return generateHTMLFooter(metadataLine, timestamp, includeTimestamp);

    case 'text':
      return generateTextFooter(metadataLine, timestamp, includeTimestamp);

    default:
      throw new Error(`Unsupported format: ${format}`);
  }
}

/**
 * Generate Markdown footer
 */
function generateMarkdownFooter(metadataLine, timestamp, includeTimestamp) {
  let footer = '\n---\n\n';
  footer += '*Generated by OpsPal by RevPal*\n\n';
  footer += `${metadataLine}\n`;
  if (includeTimestamp) {
    footer += `\nGenerated: ${timestamp}\n`;
  }
  return footer;
}

/**
 * Generate HTML footer
 */
function generateHTMLFooter(metadataLine, timestamp, includeTimestamp) {
  let footer = '<footer style="margin-top: 40px; padding: 20px; border-top: 2px solid #ddd; text-align: center; color: #666;">\n';
  footer += '  <p style="font-weight: bold; margin-bottom: 10px;">Generated by OpsPal by RevPal</p>\n';
  footer += `  <p style="font-size: 14px;">${metadataLine}</p>\n`;
  if (includeTimestamp) {
    footer += `  <p style="font-size: 12px; color: #999;">Generated: ${timestamp}</p>\n`;
  }
  footer += '</footer>';
  return footer;
}

/**
 * Generate plain text footer
 */
function generateTextFooter(metadataLine, timestamp, includeTimestamp) {
  let footer = '\n' + '='.repeat(80) + '\n';
  footer += 'Generated by OpsPal by RevPal\n\n';
  footer += `${metadataLine}\n`;
  if (includeTimestamp) {
    footer += `Generated: ${timestamp}\n`;
  }
  footer += '='.repeat(80) + '\n';
  return footer;
}

/**
 * Generate simple one-line footer (for CSV or compact formats)
 *
 * @param {string} tool - Tool name
 * @param {string} [version] - Tool version
 * @returns {string} One-line footer
 *
 * @example
 * generateSimpleFooter('CPQ Assessment', 'v2.0')
 * // Returns: "Generated by OpsPal by RevPal | CPQ Assessment v2.0 | 2025-10-09T12:34:56.789Z"
 */
function generateSimpleFooter(tool, version) {
  if (!tool) {
    throw new Error('Tool name is required for report footer');
  }

  const timestamp = new Date().toISOString();
  const toolWithVersion = version ? `${tool} ${version}` : tool;

  return `Generated by OpsPal by RevPal | ${toolWithVersion} | ${timestamp}`;
}

/**
 * Get branding text only (no metadata)
 *
 * @param {string} [format='markdown'] - Output format
 * @returns {string} Branding text
 */
function getBranding(format = 'markdown') {
  switch (format) {
    case 'markdown':
      return '*Generated by OpsPal by RevPal*';
    case 'html':
      return '<p style="font-weight: bold;">Generated by OpsPal by RevPal</p>';
    case 'text':
      return 'Generated by OpsPal by RevPal';
    default:
      return 'Generated by OpsPal by RevPal';
  }
}

module.exports = {
  generateFooter,
  generateSimpleFooter,
  getBranding
};

// CLI usage for testing
if (require.main === module) {
  console.log('=== Markdown Footer ===');
  console.log(generateFooter({
    tool: 'CPQ Assessment Framework',
    version: 'v2.0',
    method: 'API',
    reportType: 'Executive Summary'
  }));

  console.log('\n=== HTML Footer ===');
  console.log(generateFooter({
    tool: 'Automation Auditor',
    version: 'v1.0',
    format: 'html'
  }));

  console.log('\n=== Text Footer ===');
  console.log(generateFooter({
    tool: 'Data Operations',
    method: 'Bulk API',
    format: 'text'
  }));

  console.log('\n=== Simple Footer ===');
  console.log(generateSimpleFooter('Contract Renewal Import', 'v1.0'));
}
